from functools import lru_cache

def wordBreakIi(data):
    lines = (data or "").splitlines()
    s = lines[0].strip() if lines else ""
    words = lines[1].split() if len(lines) > 1 else []
    word_set = set(words)

    @lru_cache(maxsize=None)
    def dfs(i):
        if i == len(s):
            return [""]
        out = []
        for j in range(len(s), i, -1):
            part = s[i:j]
            if part not in word_set:
                continue
            tails = dfs(j)
            for t in tails:
                out.append(part if not t else part + " " + t)
        return out

    ans = dfs(0)
    # Prefer longer first token first to align expected sample ordering.
    ans = sorted(set(ans), key=lambda x: (-len(x.split()[0]) if x else 0, x))
    return "\n".join(ans)

