function wordBreakIi(data) {
    const [s, wordDict] = data.split('\n');
    const result = [];
    const wordSet = new Set(wordDict.split(' '));
    function backtrack(start, path) {
        if (start === s.length) {
            result.push(path.join(' '));
            return;
        }
        for (let end = start + 1; end <= s.length; end++) {
            const word = s.slice(start, end);
            if (wordSet.has(word)) {
                path.push(word);
                backtrack(end, path);
                path.pop();
            }
        }
    }
    backtrack(0, []);
    return result.join('\n');
}

