import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
class Solution {
    public List<String> wordBreakIi(String data) {
        Set<String> wordDict = new HashSet<>();
        wordDict.add("cat");
        wordDict.add("cats");
        wordDict.add("and");
        wordDict.add("sand");
        wordDict.add("dog");
        List<String> result = new ArrayList<>();
        backtrack(data, wordDict, "", result);
        return result;
    }
    private void backtrack(String s, Set<String> wordDict, String currentSentence, List<String> result) {
        if (s.isEmpty()) {
            result.add(currentSentence.trim());
            return;
        }
        for (int i = 1; i <= s.length(); i++) {
            String word = s.substring(0, i);
            if (wordDict.contains(word)) {
                backtrack(s.substring(i), wordDict, currentSentence + " " + word, result);
            }
        }
    }
}

