    vector<string> wordBreakIi(string s, unordered_set<string>& wordDict) {
        vector<string> result;
        vector<string> current;
        backtrack(s, wordDict, 0, current, result);
        return result;
    }
    void backtrack(string& s, unordered_set<string>& wordDict, int start, vector<string>& current, vector<string>& result) {
        if (start == s.size()) {
            string sentence;
            for (const string& word : current) {
                sentence += word + " ";
            }
            sentence.pop_back(); // remove the last space
            result.push_back(sentence);
            return;
        }
        for (int end = start + 1; end <= s.size(); ++end) {
            string word = s.substr(start, end - start);
            if (wordDict.count(word)) {
                current.push_back(word);
                backtrack(s, wordDict, end, current, result);
                current.pop_back();
            }
        }
    }
}
