func wordBreakIi(data string, wordDict []string) []string {
    wordSet := make(map[string]struct{})
    for _, word := range wordDict {
        wordSet[word] = struct{}{}
    }

    var result []string
    var backtrack func(start int, path []string)
    backtrack = func(start int, path []string) {
        if start == len(data) {
            result = append(result, strings.Join(path, " "))
            return
        }
        for end := start + 1; end <= len(data); end++ {
            word := data[start:end]
            if _, exists := wordSet[word]; exists {
                backtrack(end, append(path, word))
            }
        }
    }
    backtrack(0, []string{})
    return result
}

