    vector<string> wordBreakIi(string data, unordered_set<string>& wordDict) {
        unordered_map<int, vector<string>> memo;
        return wordBreakHelper(data, wordDict, 0, memo);
    }
    private:
    vector<string> wordBreakHelper(string& s, unordered_set<string>& wordDict, int start, unordered_map<int, vector<string>>& memo) {
        if (memo.count(start)) return memo[start];
        vector<string> result;
        if (start == s.size()) {
            result.push_back("");
            return result;
        }
        for (int end = start + 1; end <= s.size(); ++end) {
            string word = s.substr(start, end - start);
            if (wordDict.count(word)) {
                vector<string> sublist = wordBreakHelper(s, wordDict, end, memo);
                for (string& sub : sublist) {
                    result.push_back(word + (sub.empty() ? "" : " ") + sub);
                }
            }
        }
        memo[start] = result;
        return result;
    }
}
