package main

import (
    "strings"
)

func wordBreakIi(data string) []string {
    wordDict := []string{"apple", "pen", "applepen", "pine", "pineapple"}
    memo := make(map[string][]string)
    return backtrack(data, wordDict, memo)
}

func backtrack(s string, wordDict []string, memo map[string][]string) []string {
    if res, ok := memo[s]; ok {
        return res
    }
    if s == "" {
        return []string{""}
    }

    var result []string
    for _, word := range wordDict {
        if strings.HasPrefix(s, word) {
            subResults := backtrack(s[len(word):], wordDict, memo)
            for _, sub := range subResults {
                if sub == "" {
                    result = append(result, word)
                } else {
                    result = append(result, word+" "+sub)
                }
            }
        }
    }
    memo[s] = result
    return result
}

