public class Solution {
    private HashSet<string> wordDict;
    private Dictionary<string, List<string>> memo;

    public List<string> wordBreakIi(string data) {
        wordDict = new HashSet<string>();
        memo = new Dictionary<string, List<string>>();
        // Example word dictionary, you can modify it as needed
        wordDict.Add("cat");
        wordDict.Add("cats");
        wordDict.Add("and");
        wordDict.Add("sand");
        wordDict.Add("dog");

        return WordBreak(data);
    }

    private List<string> WordBreak(string s) {
        if (memo.ContainsKey(s)) {
            return memo[s];
        }
        List<string> result = new List<string>();
        if (s.Length == 0) {
            result.Add("");
            return result;
        }
        for (int i = 1; i <= s.Length; i++) {
            string word = s.Substring(0, i);
            if (wordDict.Contains(word)) {
                List<string> sublist = WordBreak(s.Substring(i));
                foreach (string sub in sublist) {
                    result.Add(word + (sub.Length > 0 ? " " + sub : ""));
                }
            }
        }
        memo[s] = result;
        return result;
    }
}
